    <div class="fg full"><label>Compte de contrepartie</label><select id="e-cpt-ctr" style="width:100%">${PLAN.map(r=>`<option value="${r}" ${r===a.contrepartie?"selected":""}>${r}</option>`).join("")}</select></div>
